noncompliant:
// Function declared but never used
void unusedFunction() { // Noncompliant
    // Some logic that is never executed
}

// Function used only in commented code
void anotherUnusedFunction() { // Noncompliant
    // Implementation
}

int main() {
    // unusedFunction(); // commented out
    return 0;
}

compliant:
// Only declare functions that are actually used
void usedFunction() {
    // Some logic
}

int main() {
    usedFunction(); // Actually called
    return 0;
}
